class Solution:
    def hasSpecialSubstring(self, s, k):
        n = len(s)
        for i in range(n - k + 1):
            if i > 0 and s[i - 1] == s[i]:
                continue
            j = i + k
            if j < n and s[j] == s[i]:
                continue
            uniform = True
            for t in range(1, k):
                if s[i + t] != s[i]:
                    uniform = False
                    break
            if uniform:
                return True
        return False

