var hasSpecialSubstring = function(s, k) {
    const n = s.length;
    let i = 0;
    while (i < n) {
        let j = i;
        while (j < n && s[j] === s[i]) j++;
        if (j - i === k) return true;
        i = j;
    }
    return false;
};
